const input = $input.first().json;
const tool = input.tool || 'create_instagram_post';
const baseUrl = '{{SUPABASE_URL}}';
const serviceKey = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': serviceKey,
  'Authorization': 'Bearer ' + serviceKey,
  'Content-Type': 'application/json'
};

// Load credentials
const creds = await helpers.httpRequest({
  method: 'GET',
  url: baseUrl + '/rest/v1/template_credentials?template_id=eq.instagram-post&select=cred_key,cred_value',
  headers: pgHeaders
});

const credMap = {};
for (const c of (creds || [])) credMap[c.cred_key] = c.cred_value;

if (tool === 'schedule_post') {
  const caption = input.caption;
  const imageUrl = input.image_url;
  const scheduledAt = input.scheduled_at;

  if (!caption) return [{ json: { error: 'Caption ist erforderlich.' } }];
  if (!scheduledAt) return [{ json: { error: 'scheduled_at ist erforderlich (ISO 8601 oder natürliche Sprache).' } }];

  // Insert into scheduled_posts
  const result = await helpers.httpRequest({
    method: 'POST',
    url: baseUrl + '/rest/v1/scheduled_posts',
    headers: { ...pgHeaders, 'Prefer': 'return=representation' },
    body: JSON.stringify({
      platform: 'instagram',
      caption: caption,
      image_url: imageUrl || null,
      scheduled_at: scheduledAt,
      status: 'pending',
      created_by: 'agent'
    })
  });

  const post = result[0];
  return [{ json: { result: 'Post geplant für ' + scheduledAt + ' (ID: ' + post.id + ')' } }];
}

// create_instagram_post
const token = credMap.instagram_token;
const userId = credMap.instagram_user_id;

if (!token || !userId) {
  return [{ json: { error: 'Instagram-Credentials nicht konfiguriert. Bitte Token und User-ID über Credential-Flow eingeben.' } }];
}

const imageUrl = input.image_url;
const caption = input.caption;

if (!imageUrl) return [{ json: { error: 'image_url ist erforderlich.' } }];
if (!caption) return [{ json: { error: 'caption ist erforderlich.' } }];

try {
  // Step 1: Create media container
  const container = await helpers.httpRequest({
    method: 'POST',
    url: 'https://graph.facebook.com/v21.0/' + userId + '/media',
    body: {
      image_url: imageUrl,
      caption: caption,
      access_token: token
    }
  });

  if (!container.id) {
    return [{ json: { error: 'Container-Erstellung fehlgeschlagen: ' + JSON.stringify(container) } }];
  }

  // Step 2: Wait for container to be ready (poll status)
  let ready = false;
  for (let i = 0; i < 10; i++) {
    const status = await helpers.httpRequest({
      method: 'GET',
      url: 'https://graph.facebook.com/v21.0/' + container.id + '?fields=status_code&access_token=' + token
    });
    if (status.status_code === 'FINISHED') { ready = true; break; }
    if (status.status_code === 'ERROR') {
      return [{ json: { error: 'Container-Fehler: ' + JSON.stringify(status) } }];
    }
    // Wait 2 seconds
    await new Promise(r => setTimeout(r, 2000));
  }

  if (!ready) return [{ json: { error: 'Container nicht bereit nach 20 Sekunden.' } }];

  // Step 3: Publish
  const publish = await helpers.httpRequest({
    method: 'POST',
    url: 'https://graph.facebook.com/v21.0/' + userId + '/media_publish',
    body: {
      creation_id: container.id,
      access_token: token
    }
  });

  // Step 4: Get permalink
  let permalink = '';
  try {
    const media = await helpers.httpRequest({
      method: 'GET',
      url: 'https://graph.facebook.com/v21.0/' + publish.id + '?fields=permalink&access_token=' + token
    });
    permalink = media.permalink || '';
  } catch(e) { /* non-critical */ }

  return [{ json: {
    result: 'Instagram-Post veröffentlicht!',
    post_id: publish.id,
    permalink: permalink
  } }];
} catch(e) {
  return [{ json: { error: 'Instagram API Fehler: ' + e.message } }];
}
